//! C++ SDK header emitter — turns the raw schema dump into ready-to-use
//! classes with `SCHEMA_FIELD` accessors.
//!
//! # What this produces
//!
//! For each schema module (e.g. `client.dll`) we emit a single header
//! `sdk/<module>.hpp` whose contents look like this:
//!
//! ```cpp
//! // Auto-generated by cs2-universal-dumper. Do not edit.
//! //
//! // build_number: 14152
//! // generated_at: 2026-04-21T22:16:38+01:00
//! //
//! // Drop this header into your internal cheat and call schema fields with:
//! //
//! //     auto* pawn = some_pawn_pointer;
//! //     int  hp    = pawn->m_iHealth();
//! //     pawn->m_iHealth() = 100;
//! //
//! // The macros below produce inline accessors that compute
//! //     reinterpret_cast<T&>(*((std::byte*)this + offset))
//! // so they are zero-overhead in release builds.
//!
//! #pragma once
//! #include "cs2sdk_macros.hpp"
//!
//! namespace cs2::sdk::client {
//!     class C_BasePlayerPawn;
//!
//!     class C_CSPlayerPawn : public C_BasePlayerPawn {
//!     public:
//!         SCHEMA_FIELD(int32_t,  m_iHealth,        0x344)
//!         SCHEMA_FIELD(QAngle,   m_angEyeAngles,   0x1334)
//!     };
//! }
//! ```
//!
//! # Why this is in a separate emitter
//!
//! The existing `output::schemas` emitter produces `constexpr offset =
//! 0xABC;` constants, which is what the original cs2-dumper consumers
//! expect. This emitter is *additive* — it leaves the original output
//! untouched and adds a parallel `sdk/` tree of header files that are
//! more ergonomic for cheat developers.
//!
//! # Type translation
//!
//! Schema type names (`"int32"`, `"CHandle< C_BaseEntity >"`,
//! `"CUtlVector< Vector >"`, ...) are mapped to their canonical C++
//! equivalents through [`map_schema_type`]. Anything we don't recognise
//! is forwarded as-is wrapped in a `using` so the file still compiles.

use std::collections::{BTreeMap, BTreeSet};
use std::fmt::Write;

use crate::analysis::{Class, Enum, SchemaMap};

use super::ident::{slugify, type_ident};

/// Render every schema module into its own `*.hpp` SDK file.
///
/// Returns a list of `(file_name, file_contents)` pairs. The file name is
/// the module slug (e.g. `client_dll.hpp`) and the contents are the full
/// header text including the build banner.
pub fn render_module_headers(
    schemas: &SchemaMap,
    build_number: Option<u32>,
    timestamp: &str,
) -> Vec<(String, String)> {
    let mut out = Vec::with_capacity(schemas.len());
    for (module, (classes, enums)) in schemas {
        let file_name = format!("{}.hpp", slugify(module));
        let body = render_one_module(module, classes, enums, build_number, timestamp);
        out.push((file_name, body));
    }
    out
}

/// Render a tiny shared header (`cs2sdk_macros.hpp`) that defines the
/// `SCHEMA_FIELD` macro family the generated headers depend on.
///
/// We emit this once instead of repeating the macros at the top of every
/// header.
pub fn render_macros_header() -> String {
    r#"// Auto-generated by cs2-universal-dumper. Do not edit.
//
// Shared macro definitions used by every generated SDK header.
// Include this file (directly or transitively) before any sdk/<module>.hpp.

#pragma once

#include <cstddef>
#include <cstdint>

namespace cs2::sdk {

    // Convert `this + offset` to a typed reference. Zero-overhead in
    // release builds; produces an lvalue you can read or assign to.
    template <typename T>
    inline T& field_ref(void* base, std::ptrdiff_t off) noexcept {
        return *reinterpret_cast<T*>(reinterpret_cast<std::byte*>(base) + off);
    }

    template <typename T>
    inline const T& field_ref(const void* base, std::ptrdiff_t off) noexcept {
        return *reinterpret_cast<const T*>(reinterpret_cast<const std::byte*>(base) + off);
    }

} // namespace cs2::sdk

// SCHEMA_FIELD(type, name, offset)
//
// Expands to a pair of inline accessors:
//
//     T&       name()       { return cs2::sdk::field_ref<T>(this, off); }
//     const T& name() const { return cs2::sdk::field_ref<T>(this, off); }
//
// Use it as: `pawn->m_iHealth() = 100;`
#define SCHEMA_FIELD(TYPE, NAME, OFFSET)                                           \
    inline TYPE&       NAME()       noexcept { return ::cs2::sdk::field_ref<TYPE>(this, (OFFSET)); } \
    inline const TYPE& NAME() const noexcept { return ::cs2::sdk::field_ref<TYPE>(this, (OFFSET)); }

// SCHEMA_PAD(name, size) — anonymous padding when you want to
// pre-declare a struct layout exactly. Optional.
#define SCHEMA_PAD(NAME, SIZE) std::byte NAME[(SIZE)]

// CS2_BUILD — set by every generated header. Use it to refuse to load
// a cheat compiled against the wrong patch:
//
//     static_assert(cs2::sdk::client::CS2_BUILD == cs2::game::current_build());
"#
    .to_string()
}

fn render_one_module(
    module: &str,
    classes: &[Class],
    enums: &[Enum],
    build_number: Option<u32>,
    timestamp: &str,
) -> String {
    let ns = slugify(module.trim_end_matches(".dll"));
    let mut s = String::with_capacity(64 * 1024);

    write_banner(&mut s, module, classes.len(), enums.len(), build_number, timestamp);
    s.push_str("#pragma once\n");
    s.push_str("#include \"cs2sdk_macros.hpp\"\n\n");

    writeln!(s, "namespace cs2::sdk::{} {{", ns).ok();
    writeln!(s).ok();

    if let Some(bn) = build_number {
        writeln!(s, "    inline constexpr std::uint32_t CS2_BUILD = {bn};\n").ok();
    }

    // Forward-declare every class up front so order-of-definition / cyclic
    // references are not a problem.
    let mut declared: BTreeSet<&str> = BTreeSet::new();
    for c in classes {
        if declared.insert(c.name.as_str()) {
            writeln!(s, "    class {};", type_ident(&c.name)).ok();
        }
    }
    writeln!(s).ok();

    // Enums first so classes can reference them.
    for e in enums {
        let underlying = match e.alignment {
            1 => "std::uint8_t",
            2 => "std::uint16_t",
            4 => "std::uint32_t",
            8 => "std::uint64_t",
            _ => continue,
        };
        writeln!(s, "    enum class {} : {} {{", type_ident(&e.name), underlying).ok();
        for m in &e.members {
            writeln!(s, "        {} = {:#X},", sanitize_enum_member(&m.name), m.value as u64).ok();
        }
        writeln!(s, "    }};\n").ok();
    }

    // Classes: emit with parent inheritance + SCHEMA_FIELD accessors.
    for c in classes {
        write_class_doc(&mut s, c);
        let parent = c
            .parent_name
            .as_deref()
            .map(type_ident)
            .map(|p| format!(" : public {}", p))
            .unwrap_or_default();
        writeln!(s, "    class {}{} {{", type_ident(&c.name), parent).ok();
        writeln!(s, "    public:").ok();
        for f in &c.fields {
            let cpp_ty = map_schema_type(&f.type_name);
            writeln!(
                s,
                "        SCHEMA_FIELD({:<32}, {:<48}, {:#X}) // {}",
                cpp_ty, f.name, f.offset, f.type_name,
            )
            .ok();
        }
        writeln!(s, "    }};\n").ok();
    }

    writeln!(s, "}} // namespace cs2::sdk::{}", ns).ok();
    s
}

fn write_banner(
    s: &mut String,
    module: &str,
    classes: usize,
    enums: usize,
    build_number: Option<u32>,
    timestamp: &str,
) {
    writeln!(s, "// Auto-generated by cs2-universal-dumper. Do not edit.").ok();
    writeln!(s, "//").ok();
    writeln!(s, "// module:        {}", module).ok();
    writeln!(s, "// classes:       {}", classes).ok();
    writeln!(s, "// enums:         {}", enums).ok();
    if let Some(bn) = build_number {
        writeln!(s, "// build_number:  {}", bn).ok();
    }
    writeln!(s, "// generated_at:  {}", timestamp).ok();
    writeln!(s, "//").ok();
    writeln!(s, "// Use:").ok();
    writeln!(s, "//   auto* pawn = reinterpret_cast<C_CSPlayerPawn*>(addr);").ok();
    writeln!(s, "//   pawn->m_iHealth() = 100;").ok();
    writeln!(s).ok();
}

fn write_class_doc(s: &mut String, c: &Class) {
    writeln!(s, "    // {}", c.name).ok();
    if let Some(parent) = &c.parent_name {
        writeln!(s, "    //   parent: {}", parent).ok();
    }
    writeln!(s, "    //   fields: {}", c.fields.len()).ok();
}

/// Map a Source 2 schema type string to its canonical C++ equivalent.
///
/// We intentionally err on the side of "leave as-is" — anything we don't
/// understand is wrapped in a forward-decl-friendly pointer or returned
/// verbatim. This keeps the header useful even for types we haven't yet
/// hand-mapped.
fn map_schema_type(raw: &str) -> String {
    let t = raw.trim();
    match t {
        "bool" => "bool".into(),
        "char" => "char".into(),
        "int8"  | "int8_t"   => "std::int8_t".into(),
        "uint8" | "uint8_t"  => "std::uint8_t".into(),
        "int16" | "int16_t"  => "std::int16_t".into(),
        "uint16"| "uint16_t" => "std::uint16_t".into(),
        "int32" | "int32_t"  => "std::int32_t".into(),
        "uint32"| "uint32_t" => "std::uint32_t".into(),
        "int64" | "int64_t"  => "std::int64_t".into(),
        "uint64"| "uint64_t" => "std::uint64_t".into(),
        "float32" | "float"  => "float".into(),
        "float64" | "double" => "double".into(),
        "Vector"             => "::Vector".into(),
        "Vector2D"           => "::Vector2D".into(),
        "Vector4D"           => "::Vector4D".into(),
        "QAngle"             => "::QAngle".into(),
        "Quaternion"         => "::Quaternion".into(),
        "Color"              => "::Color".into(),
        "CUtlString"         => "::CUtlString".into(),
        "CUtlSymbolLarge"    => "::CUtlSymbolLarge".into(),
        _ => {
            // Templated containers are extremely common in the schema:
            // CHandle< C_X >, CUtlVector< T >, CNetworkedQuantizedFloat, ...
            // Forward as-is so any type the user has defined still compiles.
            t.to_string()
        }
    }
}

fn sanitize_enum_member(raw: &str) -> String {
    let mut s = String::with_capacity(raw.len());
    for c in raw.chars() {
        if c.is_ascii_alphanumeric() || c == '_' {
            s.push(c);
        } else {
            s.push('_');
        }
    }
    if s.chars().next().map(|c| c.is_ascii_digit()).unwrap_or(false) {
        s.insert(0, '_');
    }
    s
}

/// Optional helper: collect every (class, parent) pair so a TUI / docs
/// page can render the class hierarchy. Currently unused by the emitter
/// itself; exposed for future tooling.
pub fn class_hierarchy(schemas: &SchemaMap) -> BTreeMap<String, Option<String>> {
    let mut out = BTreeMap::new();
    for (_, (classes, _)) in schemas {
        for c in classes {
            out.insert(c.name.clone(), c.parent_name.clone());
        }
    }
    out
}
